  1	import * as React from 'react';
  2	import { DASH } from '@odf/shared';
  3	import {
  4	  dateTimeFormatter,
  5	  formatPrometheusDuration,
  6	} from '@odf/shared/details-page/datetime';
  7	import {
  8	  SelectableTable,
  9	  TableColumnProps,
 10	  RowComponentType,
 11	  TableVariant,
 12	} from '@odf/shared/table';
 13	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 14	import { Td } from '@patternfly/react-table';
 15	import { AlertRowData } from './hooks';
 16	import { getSeverityIcon } from './utils';
 17	import './health-overview.scss';
 18	
 19	const RowRenderer: React.FC<RowComponentType<AlertRowData>> = ({ row }) => {
 20	  const endTimeDisplay = row.endTime
 21	    ? dateTimeFormatter.format(row.endTime)
 22	    : DASH;
 23	  // Remove seconds from duration display, show '0m' for very short durations
 24	  const durationDisplay =
 25	    formatPrometheusDuration(row.duration)
 26	      .replace(/\d+s\s*$/, '')
 27	      .trim() || '0m';
 28	  const startTimeDisplay = dateTimeFormatter.format(row.startTime);
 29	  const severityIcon = getSeverityIcon(row.severity);
 30	
 31	  return (
 32	    <>
 33	      <Td>{endTimeDisplay}</Td>
 34	      <Td>{durationDisplay}</Td>
 35	      <Td>{startTimeDisplay}</Td>
 36	      <Td>
 37	        {severityIcon}
 38	        {row.alertname}
 39	      </Td>
 40	      <Td>{row.message}</Td>
 41	    </>
 42	  );
 43	};
 44	
 45	type AlertsTableProps = {
 46	  alerts: AlertRowData[];
 47	  loaded: boolean;
 48	  error?: any;
 49	  selectedRows?: AlertRowData[];
 50	  setSelectedRows?: (rows: AlertRowData[]) => void;
 51	  isColumnSelectable?: boolean;
 52	  className?: string;
 53	};
 54	
 55	export const AlertsTable: React.FC<AlertsTableProps> = ({
 56	  alerts,
 57	  loaded,
 58	  error,
 59	  selectedRows,
 60	  setSelectedRows,
 61	  isColumnSelectable = false,
 62	  className = 'health-overview__alerts-table',
 63	}) => {
 64	  const { t } = useCustomTranslation();
 65	
 66	  const columns = React.useMemo<TableColumnProps[]>(
 67	    () => [
 68	      {
 69	        columnName: t('End time'),
 70	        sortFunction: (a, b, c) => {
 71	          const aTime = (a as AlertRowData).endTime?.getTime() || 0;
 72	          const bTime = (b as AlertRowData).endTime?.getTime() || 0;
 73	          return c === 'asc' ? aTime - bTime : bTime - aTime;
 74	        },
 75	      },
 76	      {
 77	        columnName: t('Duration'),
 78	        sortFunction: (a, b, c) => {
 79	          const diff =
 80	            (b as AlertRowData).duration - (a as AlertRowData).duration;
 81	          return c === 'asc' ? -diff : diff;
 82	        },
 83	      },
 84	      {
 85	        columnName: t('Start time'),
 86	        sortFunction: (a, b, c) => {
 87	          const diff =
 88	            (b as AlertRowData).startTime.getTime() -
 89	            (a as AlertRowData).startTime.getTime();
 90	          return c === 'asc' ? -diff : diff;
 91	        },
 92	      },
 93	      {
 94	        columnName: t('Check'),
 95	        sortFunction: (a, b, c) => {
 96	          const cmp = (a as AlertRowData).alertname.localeCompare(
 97	            (b as AlertRowData).alertname
 98	          );
 99	          return c === 'asc' ? cmp : -cmp;
100	        },
101	      },
102	      {
103	        columnName: t('Details'),
104	      },
105	    ],
106	    [t]
107	  );
108	
109	  return (
110	    <SelectableTable
111	      rows={alerts}
112	      columns={columns}
113	      RowComponent={RowRenderer}
114	      selectedRows={selectedRows}
115	      setSelectedRows={setSelectedRows}
116	      loaded={loaded}
117	      loadError={error}
118	      initialSortColumnIndex={2}
119	      borders={true}
120	      variant={TableVariant.COMPACT}
121	      className={className}
122	      isColumnSelectableHidden={!isColumnSelectable}
123	    />
124	  );
125	};

